import{_ as s,o as a,c as e,a5 as o}from"./chunks/framework.B5tqjWbr.js";const S=JSON.parse('{"title":"THD 谐波分析仿真 -- SPWM vs SVPWM vs 六步方波","description":"","frontmatter":{"title":"THD 谐波分析仿真 -- SPWM vs SVPWM vs 六步方波","date":"2026-07-02T00:00:00.000Z","section":"电机控制","chapter":"02-Simulations","chapterTitle":"仿真专题","category":"电机控制","tags":["imported"],"source":"motor","sourcePath":"frontend/src/components/simulations/THDSim.vue","status":"learning","visibility":"public","summary":"Imported from frontend/src/components/simulations/THDSim.vue","chapterOrder":20},"headers":[],"relativePath":"content/motor/simulations/THDSim.md","filePath":"content/motor/simulations/THDSim.md","lastUpdated":null}'),n={name:"content/motor/simulations/THDSim.md"};function r(i,t,m,d,p,l){return a(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="thd-谐波分析仿真-spwm-vs-svpwm-vs-六步方波" tabindex="-1">THD 谐波分析仿真 -- SPWM vs SVPWM vs 六步方波 <a class="header-anchor" href="#thd-谐波分析仿真-spwm-vs-svpwm-vs-六步方波" aria-label="Permalink to &quot;THD 谐波分析仿真 -- SPWM vs SVPWM vs 六步方波&quot;">​</a></h1><h4 id="thd-谐波分析仿真-spwm-vs-svpwm-vs-六步方波-1" tabindex="-1">THD 谐波分析仿真 -- SPWM vs SVPWM vs 六步方波 <a class="header-anchor" href="#thd-谐波分析仿真-spwm-vs-svpwm-vs-六步方波-1" aria-label="Permalink to &quot;THD 谐波分析仿真 -- SPWM vs SVPWM vs 六步方波&quot;">​</a></h4><h2 id="thd-wthd-与调制策略谐波分析" tabindex="-1">THD / WTHD 与调制策略谐波分析 <a class="header-anchor" href="#thd-wthd-与调制策略谐波分析" aria-label="Permalink to &quot;THD / WTHD 与调制策略谐波分析&quot;">​</a></h2><p>**可解释谐波模型：**六步方波按傅里叶级数建模：相电压只保留 6k±1 次低频谐波，且 Vn/V1 ≈ 1/n，因此 5次≈20%、7次≈14.3%、11次≈9.1%。3、9、15 次三次倍频零序在三相线电压/电机绕组中抵消。</p><p>**THD / WTHD：**THD = √(Σn&gt;1Vn²) / V1 × 100%，直接衡量电压非正弦程度；WTHD = √(Σn&gt;1(Vn/n)²) / V1 × 100%，用 1/n 近似电机电感对高频电压谐波的电流衰减，更适合学习“电压谐波会变成多少电流纹波”。</p><p>**SPWM / SVPWM：**在线性区，低频 5、7、11、13 次主要被调制策略抑制，显著能量集中在载波及其边带；本图只画低频学习窗口，因此 SPWM/SVPWM 数值远小于六步。SVPWM 通过零序注入扩展线性调制区，基波利用率约为 SPWM 的 1.155 倍。</p><p>**工程结论：**六步的母线利用率最高但低次谐波和转矩脉动最大；SVPWM 是伺服/FOC 中最常用折中。常见误区是只看 THD 不看频率位置：同样 THD，高频谐波更容易被绕组电感滤掉，所以 WTHD 更接近电流质量。</p>',7)])])}const T=s(n,[["render",r]]);export{S as __pageData,T as default};
